sql:
SELECT AVG(cumulative_gpa) AS average_gpa
FROM students_status
WHERE graduation_year = 2023;

external_knowledge:
-"decent travel time" corresponds to a travel time of 1 or more; 
-"relatively good health" corresponds to a health status of 3 or more; 
-"average performance score" is the average of math score, study time, and health status.
